using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.Transfers.Domain.Entities;
namespace verii_metivon_api.Modules.Transfers.Infrastructure.Persistence.Configurations;
public sealed class TransferOrderConfiguration:IEntityTypeConfiguration<TransferOrder>{public void Configure(EntityTypeBuilder<TransferOrder>b){b.ToTable("RII_TRANSFER_ORDERS");b.HasIndex(x=>x.TransferNumber).IsUnique();b.Property(x=>x.TransferNumber).HasMaxLength(40).IsRequired();b.HasOne(x=>x.FromWarehouse).WithMany().HasForeignKey(x=>x.FromWarehouseId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.ToWarehouse).WithMany().HasForeignKey(x=>x.ToWarehouseId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class TransferOrderLineConfiguration:IEntityTypeConfiguration<TransferOrderLine>{public void Configure(EntityTypeBuilder<TransferOrderLine>b){b.ToTable("RII_TRANSFER_ORDER_LINES");b.HasIndex(x=>new{x.TransferOrderId,x.LineNumber}).IsUnique();foreach(var p in new[]{nameof(TransferOrderLine.RequestedQuantity),nameof(TransferOrderLine.ShippedQuantity),nameof(TransferOrderLine.ReceivedQuantity)})b.Property(p).HasPrecision(24,8);b.HasOne(x=>x.TransferOrder).WithMany(x=>x.Lines).HasForeignKey(x=>x.TransferOrderId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.FromLocation).WithMany().HasForeignKey(x=>x.FromLocationId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.ToLocation).WithMany().HasForeignKey(x=>x.ToLocationId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class TransferParameterSettingsConfiguration:IEntityTypeConfiguration<TransferParameterSettings>{public void Configure(EntityTypeBuilder<TransferParameterSettings>b){b.ToTable("RII_TRANSFER_PARAMETERS",t=>{t.HasCheckConstraint("CK_RII_TRANSFER_PARAMETERS_TRANSIT_DAYS","[DefaultTransitDays] >= 0 AND [DefaultTransitDays] <= 3650");t.HasCheckConstraint("CK_RII_TRANSFER_PARAMETERS_MAX_LINES","[MaximumLinesPerTransfer] >= 1 AND [MaximumLinesPerTransfer] <= 10000");});b.HasKey(x=>x.Id);b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>new{x.BranchId,x.WarehouseId}).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.InventoryCurrencyCode).HasMaxLength(3).IsUnicode(false).IsRequired();b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchId).OnDelete(DeleteBehavior.Restrict);b.HasOne(x=>x.Warehouse).WithMany().HasForeignKey(x=>x.WarehouseId).OnDelete(DeleteBehavior.Restrict);}}
